import{f as a,g as n,J as s}from"./common-03e46d7f.js";const e='{"title":"搭建博客记录","frontmatter":{"date":"2022-06-10","title":"搭建博客记录","tags":["tool"],"describe":"使用vitepress搭建博客，通过github pages生成在线访问地址"},"headers":[{"level":2,"title":"vitepress文档","slug":"vitepress文档"},{"level":3,"title":"配置","slug":"配置"},{"level":3,"title":"markdown拓展","slug":"markdown拓展"},{"level":3,"title":"创建博客项目","slug":"创建博客项目"},{"level":3,"title":"发布到github pages","slug":"发布到github-pages"},{"level":3,"title":"发布到gitlab pages","slug":"发布到gitlab-pages"}],"relativePath":"docs/tool/blog.md","lastUpdated":1660910176852.0195}';var t={};const p=[s('<p>因为是使用vitepress搭建博客，所以先需要了解一下<a href="https://vitejs.cn/vitepress/" target="_blank" rel="noopener noreferrer">vitepress</a></p><h2 id="vitepress文档"><a class="header-anchor" href="#vitepress文档" aria-hidden="true">#</a> vitepress文档</h2><h3 id="配置"><a class="header-anchor" href="#配置" aria-hidden="true">#</a> 配置</h3><ul><li><p>文档目录下创建一个 <code>.vuepress</code> 目录，存放所有 <code>VuePress</code> 相关的文件</p></li><li><p>配置文件 <code>.vuepress/config.js</code>，导出一个 JavaScript 对象</p><div class="language-js"><pre><code>module<span class="token punctuation">.</span>exports <span class="token operator">=</span> <span class="token punctuation">{</span>\n  <span class="token literal-property property">title</span><span class="token operator">:</span> <span class="token string">&#39;Hello VitePress&#39;</span><span class="token punctuation">,</span>\n  <span class="token literal-property property">description</span><span class="token operator">:</span> <span class="token string">&#39;Just playing around.&#39;</span>\n<span class="token punctuation">}</span>\n</code></pre></div></li></ul><h3 id="markdown拓展"><a class="header-anchor" href="#markdown拓展" aria-hidden="true">#</a> markdown拓展</h3><p><a href="https://vitejs.cn/vitepress/guide/markdown.html" target="_blank" rel="noopener noreferrer">原文链接</a></p><ul><li><p>文件夹下的 <code>index.md</code> 文件都会被自动编译为 <code>index.html</code>，对应的链接将被视为 <code>/</code></p><div class="language-bash"><pre><code><span class="token builtin class-name">.</span>\n├─ index.md\n├─ foo\n│  ├─ index.md\n│  ├─ one.md\n│  └─ two.md\n└─ bar\n  ├─ index.md\n  ├─ three.md\n  └─ four.md\n</code></pre></div><p>会被编译为</p><div class="language-bash"><pre><code><span class="token punctuation">[</span>Home<span class="token punctuation">]</span><span class="token punctuation">(</span>/<span class="token punctuation">)</span> <span class="token operator">&lt;</span><span class="token operator">!</span>-- 跳转到根目录的index.md --<span class="token operator">&gt;</span>\n<span class="token punctuation">[</span>foo<span class="token punctuation">]</span><span class="token punctuation">(</span>/foo/<span class="token punctuation">)</span> <span class="token operator">&lt;</span><span class="token operator">!</span>-- 跳转到 foo 文件夹的 index.html--<span class="token operator">&gt;</span>\n<span class="token punctuation">[</span>foo heading<span class="token punctuation">]</span><span class="token punctuation">(</span>./<span class="token comment">#heading) &lt;!-- 跳转到 foo/index.html 的特定标题位置 --&gt;</span>\n<span class="token punctuation">[</span>bar - three<span class="token punctuation">]</span><span class="token punctuation">(</span><span class="token punctuation">..</span>/bar/three<span class="token punctuation">)</span> <span class="token operator">&lt;</span><span class="token operator">!</span>-- 你可以忽略扩展名 --<span class="token operator">&gt;</span>\n<span class="token punctuation">[</span>bar - three<span class="token punctuation">]</span><span class="token punctuation">(</span><span class="token punctuation">..</span>/bar/three.md<span class="token punctuation">)</span> <span class="token operator">&lt;</span><span class="token operator">!</span>-- 具体文件可以使用 .md 结尾（推荐）--<span class="token operator">&gt;</span>\n<span class="token punctuation">[</span>bar - four<span class="token punctuation">]</span><span class="token punctuation">(</span><span class="token punctuation">..</span>/bar/four.html<span class="token punctuation">)</span> <span class="token operator">&lt;</span><span class="token operator">!</span>-- 也可以用 .html--<span class="token operator">&gt;</span>\n</code></pre></div></li><li><p>Frontmatter</p><p>任何包含YAML frontmatter块的Markdown文件都将由gray-matter处理。Frontmatter块必须位于在Markdown文件的顶部，必须是有效的YAML格式，放置在三点划线之间。例如：</p><div class="language-md"><pre><code><span class="token front-matter-block"><span class="token punctuation">---</span>\n<span class="token front-matter yaml language-yaml">title: Docs with VitePress\neditLink: true</span>\n<span class="token punctuation">---</span></span>\n\n</code></pre></div></li></ul><h3 id="创建博客项目"><a class="header-anchor" href="#创建博客项目" aria-hidden="true">#</a> 创建博客项目</h3><blockquote><p>可以使用<a href="https://vitejs.cn/vitepress/" target="_blank" rel="noopener noreferrer">vitepress官方文档</a>按照步骤创建，我是直接在github上克隆别人已有的博客进行修改<br> 博客地址：<a href="http://jexlau.github.io/blog/" target="_blank" rel="noopener noreferrer">jexlau.github.io/blog/</a></p></blockquote><ul><li><p>克隆项目</p><div class="language-bash"><pre><code><span class="token function">git</span> clone https://github.com/JexLau/blog.git\n<span class="token builtin class-name">cd</span> blog\n\n<span class="token comment"># 安装依赖</span>\n<span class="token function">yarn</span>\n\n<span class="token comment"># 在本地启动服务器</span>\n<span class="token function">yarn</span> dev\n\n<span class="token comment"># 构建静态文件 &gt; .vitepress/dist</span>\n<span class="token function">yarn</span> build\n</code></pre></div></li><li><p>修改配置</p><ul><li><p>.vitepress 是项目页面的配置，可以根据自己的想法更改</p></li><li><p>docs中用于存放自己的md文档，存放你自己的文档，注意格式如下</p><div class="language-md"><pre><code><span class="token front-matter-block"><span class="token punctuation">---</span>\n<span class="token front-matter yaml language-yaml">date: 2022-06-10\ntitle: 搭建博客记录\ntags:\n  - 博客\ndescribe: 使用vitepress搭建博客，通过github pages生成在线访问地址</span>\n<span class="token punctuation">---</span></span>\n</code></pre></div></li><li><p>more中用于存放导航栏的标签</p></li></ul></li></ul><h3 id="发布到github-pages"><a class="header-anchor" href="#发布到github-pages" aria-hidden="true">#</a> 发布到github pages</h3><ul><li><p>github创建blog仓库<code>Create a new repository</code></p></li><li><p>先将本地代码推到远程仓库，便于存储及之后修改</p></li><li><p>修改deploy.sh脚本文件</p><ul><li><p>先将本地文件提交到github master分支</p></li><li><p><a href="http://xn--deploy-2g0js76l.sh" target="_blank" rel="noopener noreferrer">修改deploy.sh</a>，将github地址改为你自己的地址</p><div class="language-bash"><pre><code><span class="token comment"># 如果发布到 https://&lt;USERNAME&gt;.github.io/&lt;REPO&gt;</span>\n<span class="token function">git</span> push -f https://github.com/wang1xiang/blog.git master:gh-pages\n</code></pre></div></li><li><p>yarn deploy发布，如果没有成功，可以按照deploy.sh的文件一步步执行，看是哪里的问题</p></li></ul></li><li><p>查看发布成功后的地址<a href="https://wang1xiang.github.io/blog/" target="_blank" rel="noopener noreferrer">https://wang1xiang.github.io/blog/</a>，如果没有刷新，强制刷新一下试试</p></li></ul><h3 id="发布到gitlab-pages"><a class="header-anchor" href="#发布到gitlab-pages" aria-hidden="true">#</a> 发布到gitlab pages</h3>',13)];t.render=function(s,e,t,o,l,r){return a(),n("div",null,p)};export{e as __pageData,t as default};
